class Solution {
public:
    int maxConsecutiveAnswers(string answerKey, int k) {
        return max(consecutive(answerKey, 'T', k), consecutive(answerKey, 'F', k));
    }

    int consecutive(string& answerKey, char target, int k) {
        int left = 0, max_len = 0, count = 0;
        for (int right = 0; right < answerKey.size(); ++right) {
            if (answerKey[right] != target) count++;
            while (count > k) {
                if (answerKey[left] != target) count--;
                left++;
            }
            max_len = max(max_len, right - left + 1);
        }
        return max_len;
    }
};
